output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
SELECT ?person ?degree ?degreeLabel WHERE {
  VALUES ?office {
    wd:Q1840570 wd:Q1372518 wd:Q1383921 wd:Q884309 wd:Q501113 wd:Q2508716
  }
  ?person wdt:P39 ?office .
  FILTER NOT EXISTS {
    ?person p:P39 ?statement ; pq:P582 ?end
  }
  ?person wdt:P512 ?degree .
  ?degree rdfs:label ?degreeLabel .
  FILTER(LANG(?degreeLabel) = 'en')
}

