SELECT ?person ?degree
WHERE {
  ?office wdt:P31 wd:Q19007 .  # Governor positions
  ?office wdt:P17 wd:Q16 .    # Office in Australia
  ?person wdt:P39 ?office .   # Person holds office
  FILTER NOT EXISTS { ?person p:P39 ?statement; pq:P582 ?end }
  ?person wdt:P512 ?degree .  # Academic degree
}

